const formatTime = (secs) => {
    const h = Math.floor(secs / 3600).toString().padStart(2, '0');
    const m = Math.floor((secs % 3600) / 60).toString().padStart(2, '0');
    const s = (secs % 60).toString().padStart(2, '0');
    return `${h}:${m}:${s}`;
};

const Offers = () => {
    const [cart, setCart] = useState(JSON.parse(localStorage.getItem('dmartCart') || '[]'));
    const [activeTab, setActiveTab] = useState('all');
    const [liked, setLiked] = useState([]);
    const [timers, setTimers] = useState(() => {
        const initial = {};
        FLASH_OFFERS.forEach(o => initial[o.id] = o.timer);
        HOT_DEALS.forEach(d => initial[d.id] = d.timer);
        return initial;
    });
    const navigate = useNavigate();
    const [toast, setToast] = useState('');

    useEffect(() => {
        const interval = setInterval(() => {
            setTimers(prev => {
                const newTimers = { ...prev };
                let updated = false;
                FLASH_OFFERS.forEach(o => {
                    if (newTimers[o.id] > 0) {
                        newTimers[o.id]--;
                        updated = true;
                    }
                });
                HOT_DEALS.forEach(d => {
                    if (newTimers[d.id] > 0) {
                        newTimers[d.id]--;
                        updated = true;
                    }
                });
                return updated ? newTimers : prev;
            });
        }, 1000);
        return () => clearInterval(interval);
    }, []);

    const showToast = (msg) => {
        setToast(msg);
        setTimeout(() => setToast(''), 2500);
    };

    const updateCart = (item, delta) => {
        const newCart = [...cart];
        const idx = newCart.findIndex(c => c.id === item.id);
        if (idx > -1) {
            newCart[idx].qty += delta;
            if (newCart[idx].qty <= 0) newCart.splice(idx, 1);
        } else if (delta > 0) {
            newCart.push({
                id: item.id,
                name: item.name,
                price: item.newP ?? item.price,
                image: item.image || '',
                qty: 1
            });
            showToast(`✅ ${item.name} added!`);
        }
        setCart(newCart);
        localStorage.setItem('dmartCart', JSON.stringify(newCart));
    };

    const copyCoupon = () => {
        navigator.clipboard?.writeText('DMART50');
        showToast('📋 Coupon code DMART50 copied!');
    };

    return (
        <div className="min-h-screen bg-slate-50 pb-24 animate-fadeIn">
            <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-slate-100 flex items-center justify-between px-5 py-4 max-w-[480px] mx-auto shadow-sm">
                <button onClick={() => navigate('/home')} className="w-10 h-10 bg-slate-100 border border-slate-200 flex items-center justify-center rounded-xl text-slate-700 active:scale-90 transition-all">
                    <ArrowLeft className="w-5 h-5" />
                </button>
                <h1 className="text-xl font-black text-slate-900 tracking-tight">Offers &amp; Deals</h1>
                <button onClick={() => navigate('/products')} className="w-10 h-10 bg-slate-100 border border-slate-200 flex items-center justify-center rounded-xl text-slate-700 active:scale-90 transition-all">
                    <Search className="w-5 h-5" />
                </button>
            </header>

            <div className="flex gap-2 px-5 py-4 overflow-x-auto scrollbar-hide">
                {[{ id: 'all', label: 'All Offers' }, { id: 'fresh', label: '🍎 Fresh' }, { id: 'snacks', label: '🍟 Snacks' }, { id: 'dairy', label: '🥛 Dairy' }, { id: 'daily', label: '🛒 Daily' }].map(t => (
                    <button
                        key={t.id}
                        onClick={() => setActiveTab(t.id)}
                        className={`px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest whitespace-nowrap transition-all ${activeTab === t.id ? 'bg-green-600 text-white shadow-lg shadow-green-100 scale-105' : 'bg-white text-slate-500 border border-slate-100'}`}
                    >
                        {t.label}
                    </button>
                ))}
            </div>

            <div className="px-5 mb-6">
                <div onClick={copyCoupon} className="bg-gradient-to-br from-purple-600 to-purple-500 rounded-3xl p-5 flex items-center gap-4 cursor-pointer shadow-xl shadow-purple-200 active:scale-95 transition-all">
                    <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center text-white backdrop-blur-sm">
                        <Ticket className="w-6 h-6" />
                    </div>
                    <div className="flex-1 text-white">
                        <h4 className="font-extrabold text-base mb-1">Use Code: <span className="font-black text-purple-100 bg-black/20 px-2 py-0.5 rounded-lg border border-white/10">DMART50</span></h4>
                        <p className="text-xs font-medium text-purple-100/90 leading-tight">Get ₹50 off on orders above ₹399</p>
                    </div>
                    <Copy className="w-5 h-5 text-purple-200" />
                </div>
            </div>

            <div className="px-5 mb-4 flex items-center gap-2">
                <h2 className="text-lg font-black text-slate-900 flex items-center gap-2"><Flame className="w-5 h-5 text-red-500" fill="currentColor" /> Flash Sales</h2>
                <span className="bg-red-500 text-white text-[10px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest">Limited</span>
            </div>

            <div className="grid grid-cols-2 gap-4 px-5 mb-8">
                {FLASH_OFFERS.filter(o => activeTab === 'all' || o.cat === activeTab).map(o => {
                    const qty = cart.find(c => c.id === o.id)?.qty || 0;
                    return (
                        <div key={o.id} className="bg-white rounded-3xl overflow-hidden border border-slate-100 shadow-sm relative animate-slideUp">
                            <div className="aspect-[4/3] bg-green-50 relative overflow-hidden">
                                <img
                                    src={o.image}
                                    alt={o.name}
                                    className="w-full h-full object-cover"
                                />
                                <span className="absolute top-2 left-2 bg-red-500 text-white text-[10px] font-black px-2 py-1 rounded-lg z-10">{o.off}% OFF</span>
                                <div className="absolute bottom-2 right-2 bg-black/70 backdrop-blur-md text-white text-[9px] font-bold px-2 py-1 rounded-lg flex items-center gap-1 z-10">
                                    <Clock className="w-3 h-3 text-red-400" /> {timers[o.id] !== undefined ? formatTime(timers[o.id]) : '--:--:--'}
                                </div>
                            </div>
                            <div className="p-3">
                                <h4 className="font-bold text-slate-800 text-sm mb-1 truncate">{o.name}</h4>
                                <div className="flex items-end gap-1.5 mb-2">
                                    <span className="font-black text-green-700 text-base leading-none">₹{o.newP}</span>
                                    <span className="font-bold text-slate-400 text-[10px] line-through">₹{o.oldP}</span>
                                </div>
                                <div className="flex items-center gap-1 mb-3">
                                    <div className="flex text-yellow-400">
                                        {[...Array(5)].map((_, i) => <Star key={i} className="w-2.5 h-2.5" fill={i < Math.round(o.rating) ? 'currentColor' : 'none'} />)}
                                    </div>
                                    <span className="text-[9px] font-bold text-slate-400">({o.reviews})</span>
                                </div>
                                <div className="flex items-center justify-between">
                                    {qty > 0 ? (
                                        <div className="flex items-center bg-green-50 border border-green-100 rounded-xl h-8 overflow-hidden shadow-sm flex-1 mr-2">
                                            <button onClick={() => updateCart(o, -1)} className="w-7 h-full flex items-center justify-center text-green-600 hover:bg-green-100 active:scale-90 transition-all"><Minus className="w-3 h-3" /></button>
                                            <span className="flex-1 text-center text-xs font-black text-green-800">{qty}</span>
                                            <button onClick={() => updateCart(o, 1)} className="w-7 h-full flex items-center justify-center text-green-600 hover:bg-green-100 active:scale-90 transition-all"><Plus className="w-3 h-3" /></button>
                                        </div>
                                    ) : (
                                        <button onClick={() => updateCart(o, 1)} className="bg-slate-900 text-white text-[11px] font-black uppercase tracking-wider px-4 py-2 rounded-xl active:scale-95 transition-all shadow-lg flex-1 mr-2">Add</button>
                                    )}
                                    <span className="text-[9px] font-black text-green-600 uppercase tracking-tighter text-right leading-tight">Save<br />₹{((o.oldP - o.newP) * 100).toFixed(0)}</span>
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>

            <div className="px-5 mb-4">
                <h2 className="text-lg font-black text-slate-900 flex items-center gap-2">🔥 More Hot Deals</h2>
            </div>

            <div className="px-5 space-y-4">
                {HOT_DEALS.map(d => {
                    const isLiked = liked.includes(d.id);
                    return (
                    <div key={d.id} className="bg-white border border-slate-100 rounded-3xl p-4 flex gap-4 items-center shadow-sm animate-slideUp">
                        <div className="w-20 h-20 bg-green-50 rounded-2xl overflow-hidden flex items-center justify-center shrink-0">
                            <img src={d.image} alt={d.name} className="w-full h-full object-cover" />
                        </div>
                        <div className="flex-1">
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{d.cat}</span>
                            <h4 className="font-extrabold text-slate-800 text-sm mb-1">{d.name}</h4>
                            <div className="flex items-center gap-2 mb-2">
                                <span className="font-black text-slate-900 text-base">₹{d.price}</span>
                                <span className="font-bold text-slate-400 text-xs line-through">₹{d.oldP}</span>
                                <span className="bg-yellow-100 text-yellow-700 font-black text-[9px] uppercase tracking-wider px-2 py-0.5 rounded-md">{d.off}% OFF</span>
                            </div>
                            <div className="flex items-center gap-1 text-[10px] font-bold text-red-500">
                                <Clock className="w-3 h-3" /> Ends in: {timers[d.id] !== undefined ? formatTime(timers[d.id]) : '--:--:--'}
                            </div>
                        </div>
                        <div className="flex flex-col items-center gap-2 shrink-0">
                            <button
                                onClick={() => setLiked(prev => prev.includes(d.id) ? prev.filter(x => x !== d.id) : [...prev, d.id])}
                                className="w-9 h-9 rounded-full border border-slate-100 flex items-center justify-center bg-slate-50"
                            >
                                <Heart className={`w-4 h-4 ${isLiked ? 'text-red-500 fill-red-500' : 'text-slate-300'}`} />
                            </button>
                            <div className="flex text-yellow-400">
                                <Star className="w-3 h-3" fill="currentColor" />
                            </div>
                            <span className="text-[10px] font-bold text-slate-400">{d.rating} ★</span>
                            <button onClick={() => updateCart(d, 1)} className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center active:scale-90 transition-all shadow-lg shadow-slate-200">
                                <Plus className="w-5 h-5" />
                            </button>
                        </div>
                    </div>
                )})}
            </div>

            {toast && (
                <div className="fixed top-20 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-3 rounded-2xl shadow-2xl font-bold text-sm z-50 animate-slideUp flex items-center gap-2 whitespace-nowrap">
                    {toast}
                </div>
            )}

            <div className="fixed bottom-0 left-0 right-0 h-20 bg-white/80 backdrop-blur-3xl border-t border-slate-100 flex items-center justify-around px-2 max-w-[480px] mx-auto z-50">
                <button onClick={() => navigate('/home')} className="flex flex-col items-center gap-1 text-slate-400 p-2"><Home className="w-6 h-6" /><span className="text-[10px] font-black">Home</span></button>
                <button onClick={() => navigate('/products')} className="flex flex-col items-center gap-1 text-slate-400 p-2"><LayoutGrid className="w-6 h-6" /><span className="text-[10px] font-black">Shop</span></button>
                <button className="flex flex-col items-center gap-1 text-green-600 p-2 relative"><Tag className="w-6 h-6" /><span className="text-[10px] font-black">Offers</span><span className="absolute top-1 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span></button>
                <button onClick={() => navigate('/orders')} className="flex flex-col items-center gap-1 text-slate-400 p-2"><ListOrdered className="w-6 h-6" /><span className="text-[10px] font-black">Orders</span></button>
                <button onClick={() => navigate('/account')} className="flex flex-col items-center gap-1 text-slate-400 p-2"><User className="w-6 h-6" /><span className="text-[10px] font-black">Account</span></button>
            </div>
        </div>
    );
};

export default Offers;
